oxy_webhelp_navlinks = {"rbk_cdm_software_upgrade-d30753e3403":{"topics":[{"title":"Rubrik CDM release information","shortdesc":"<p class=\"shortdesc\">The Rubrik CDM release information includes details such as release date, end of         support date, and current adoption rate. You can use this information to compare the         available versions for making a decision about upgrading.<\/p>","href":"saas\/rubrik_cdm_release_information.html","attributes":{"data-id":"rubrik_cdm_release_information"},"menu":{"hasChildren":false},"tocID":"rubrik_cdm_release_information-d30753e3414","next":"rubrik_cdm_release_information-d30753e3414"},{"title":"Rolling upgrade of Rubrik CDM software","shortdesc":"<p class=\"shortdesc\">Rolling upgrades provide a zero downtime method for updating Rubrik CDM software by         processing nodes sequentially. Administrators can enable and manage this feature for         eligible clusters using <span class=\"ph\">Rubrik Security Cloud<\/span> to ensure continuous data         availability.<\/p>","href":"saas\/rolling_upgrade_rbk_cdm_software.html","attributes":{"data-id":"rolling_upgrade_rbk_cdm_software"},"menu":{"hasChildren":false},"tocID":"rolling_upgrade_rbk_cdm_software-d30753e3461","next":"rolling_upgrade_rbk_cdm_software-d30753e3461"},{"title":"Fast upgrade of Rubrik CDM software","shortdesc":"<p class=\"shortdesc\">With the fast upgrade of Rubrik CDM software running on your Rubrik cluster, you can         simultaneously upgrade all Rubrik cluster nodes. This option saves time but requires some         system downtime.<\/p>","href":"saas\/fast_upgrade_rbk_cdm_software.html","attributes":{"data-id":"fast_upgrade_rbk_cdm_software"},"menu":{"hasChildren":false},"tocID":"fast_upgrade_rbk_cdm_software-d30753e3508","topics":[]},{"title":"Upgrade preparation and prechecks","shortdesc":"<p class=\"shortdesc\">Rubrik clusters use automated prechecks to prepare for the upgrade process and         identify potential obstacles.<\/p>","href":"saas\/upgrade_preparation_and_prechecks.html","attributes":{"data-id":"upgrade_preparation_and_prechecks"},"menu":{"hasChildren":false},"tocID":"upgrade_preparation_and_prechecks-d30753e3519","next":"upgrade_preparation_and_prechecks-d30753e3519"},{"title":"Rubrik CDM software upgrade using <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\">To take advantage of the latest features and improvements that Rubrik offers, you can         upgrade the Rubrik CDM version running on any connected Rubrik cluster to the latest version         using <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/rbk_cdm_soft_upgrade_rsc.html","attributes":{"data-id":"rbk_cdm_soft_upgrade_rsc"},"menu":{"hasChildren":false},"tocID":"rbk_cdm_soft_upgrade_rsc-d30753e3576","next":"rbk_cdm_soft_upgrade_rsc-d30753e3576"},{"title":"Downloading the Rubrik cluster upgrade report","shortdesc":"<p class=\"shortdesc\">Download and view the Rubrik cluster upgrade report for monitoring or         auditing.<\/p>","href":"saas\/downloading_the_rubrik_cluster_upgrade_report.html","attributes":{"data-id":"downloading_the_rubrik_cluster_upgrade_report"},"menu":{"hasChildren":false},"tocID":"downloading_the_rubrik_cluster_upgrade_report-d30753e3685","next":"downloading_the_rubrik_cluster_upgrade_report-d30753e3685"}]}};